// skill.zig - SKILL script generation helpers for Cadence Virtuoso export.
//
// Generates SKILL (LISP-like) scripts that can be executed in the Cadence
// Virtuoso CIW (Command Interpreter Window) to export schematic data in
// a format suitable for Schemify import.
//
// This module provides:
//   - Export script generation (dumps cell/view/instances to CDL/Spectre)
//   - Utility functions for SKILL string escaping
//   - Template for common SKILL operations

const std = @import("std");

// ── SKILL String Escaping ────────────────────────────────────────────────────

/// Escape a string for embedding in a SKILL double-quoted string literal.
/// Handles: backslash, double-quote, newline.
pub fn escapeSkillString(alloc: std.mem.Allocator, input: []const u8) ![]const u8 {
    var needs_escape = false;
    for (input) |c| {
        if (c == '"' or c == '\\' or c == '\n') {
            needs_escape = true;
            break;
        }
    }
    if (!needs_escape) return try alloc.dupe(u8, input);

    var buf: std.ArrayListUnmanaged(u8) = .{};
    for (input) |c| {
        switch (c) {
            '"' => try buf.appendSlice(alloc, "\\\""),
            '\\' => try buf.appendSlice(alloc, "\\\\"),
            '\n' => try buf.appendSlice(alloc, "\\n"),
            else => try buf.append(alloc, c),
        }
    }
    return try buf.toOwnedSlice(alloc);
}

// ── Export Script Templates ──────────────────────────────────────────────────

/// Script that exports the netlist of a given cell as CDL format.
/// The user should paste this into the Virtuoso CIW.
pub const export_cdl_template =
    \\; Schemify CDL Export Script
    \\; Usage: Paste into CIW after opening the cell
    \\procedure( schemifyExportCDL(libName cellName viewName outFile)
    \\  let( (cv netlistDir)
    \\    cv = dbOpenCellViewByType(libName cellName viewName nil "r")
    \\    unless(cv
    \\      printf("ERROR: Cannot open %s/%s/%s\n" libName cellName viewName)
    \\      return(nil)
    \\    )
    \\    netlistDir = "/tmp/schemify_export"
    \\    createDir(netlistDir)
    \\    asiSetNetlistDir(netlistDir)
    \\    simulator('spectre)
    \\    design(libName cellName viewName)
    \\    createNetlist(recreateAll t)
    \\    printf("CDL exported to %s\n" outFile)
    \\    dbClose(cv)
    \\  )
    \\)
    \\
;

/// Script that enumerates instances in a schematic and prints them.
pub const enumerate_instances_template =
    \\; Schemify Instance Enumeration Script
    \\procedure( schemifyEnumInstances(libName cellName)
    \\  let( (cv instances inst)
    \\    cv = dbOpenCellViewByType(libName cellName "schematic" nil "r")
    \\    unless(cv
    \\      printf("ERROR: Cannot open %s/%s/schematic\n" libName cellName)
    \\      return(nil)
    \\    )
    \\    instances = cv~>instances
    \\    foreach( inst instances
    \\      printf("%s %s/%s %d %d\n"
    \\        inst~>name
    \\        inst~>libName
    \\        inst~>cellName
    \\        inst~>xy~>car
    \\        inst~>xy~>cadr
    \\      )
    \\    )
    \\    printf("Total: %d instances\n" length(instances))
    \\    dbClose(cv)
    \\  )
    \\)
    \\
;

/// Script that exports wire/net connectivity from a schematic.
pub const export_nets_template =
    \\; Schemify Net Export Script
    \\procedure( schemifyExportNets(libName cellName outFile)
    \\  let( (cv nets net port outPort)
    \\    cv = dbOpenCellViewByType(libName cellName "schematic" nil "r")
    \\    unless(cv
    \\      printf("ERROR: Cannot open %s/%s/schematic\n" libName cellName)
    \\      return(nil)
    \\    )
    \\    outPort = outfile(outFile "w")
    \\    nets = cv~>nets
    \\    foreach( net nets
    \\      fprintf(outPort "NET %s\n" net~>name)
    \\      foreach( port net~>instTerms
    \\        fprintf(outPort "  CONN %s %s\n" port~>inst~>name port~>name)
    \\      )
    \\    )
    \\    close(outPort)
    \\    printf("Nets exported to %s\n" outFile)
    \\    dbClose(cv)
    \\  )
    \\)
    \\
;

// ── Script Generation ────────────────────────────────────────────────────────

/// Generate a SKILL script that exports a specific cell's netlist as CDL.
pub fn generateExportScript(
    alloc: std.mem.Allocator,
    lib_name: []const u8,
    cell_name: []const u8,
    output_path: []const u8,
) ![]const u8 {
    return std.fmt.allocPrint(alloc,
        \\; Auto-generated by Schemify for Cadence Virtuoso export
        \\load("{s}")
        \\schemifyExportCDL("{s}" "{s}" "schematic" "{s}")
        \\
    , .{
        "/tmp/schemify_export.il",
        lib_name,
        cell_name,
        output_path,
    });
}

/// Generate a SKILL script that lists all cells in a library.
pub fn generateListCellsScript(
    alloc: std.mem.Allocator,
    lib_name: []const u8,
) ![]const u8 {
    return std.fmt.allocPrint(alloc,
        \\; List all cells in library: {s}
        \\let( (lib cells)
        \\  lib = ddGetObj("{s}")
        \\  when(lib
        \\    cells = lib~>cells
        \\    foreach( cell cells
        \\      printf("%s\n" cell~>name)
        \\    )
        \\    printf("Total: %d cells\n" length(cells))
        \\  )
        \\)
        \\
    , .{ lib_name, lib_name });
}

// ── Evaluator (for future SKILL expression parsing) ──────────────────────────

pub const Evaluator = struct {
    alloc: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator) Evaluator {
        return .{ .alloc = alloc };
    }

    pub fn deinit(self: *Evaluator) void {
        self.* = undefined;
    }

    /// Parse a simple SKILL property list and return key-value pairs.
    /// Format: list("key1" "val1" "key2" "val2" ...)
    pub fn parsePropertyList(self: *const Evaluator, input: []const u8) ![]const struct { key: []const u8, val: []const u8 } {
        var pairs: std.ArrayListUnmanaged(struct { key: []const u8, val: []const u8 }) = .{};
        const alloc = self.alloc;

        // Simple parser: find quoted strings in sequence
        var pos: usize = 0;
        var strings: std.ArrayListUnmanaged([]const u8) = .{};
        defer strings.deinit(alloc);

        while (pos < input.len) {
            if (input[pos] == '"') {
                pos += 1;
                const start = pos;
                while (pos < input.len and input[pos] != '"') {
                    if (input[pos] == '\\') pos += 1;
                    pos += 1;
                }
                try strings.append(alloc, input[start..pos]);
                if (pos < input.len) pos += 1;
            } else {
                pos += 1;
            }
        }

        // Pair up strings as key-value
        var i: usize = 0;
        while (i + 1 < strings.items.len) : (i += 2) {
            try pairs.append(alloc, .{ .key = strings.items[i], .val = strings.items[i + 1] });
        }

        return try pairs.toOwnedSlice(alloc);
    }
};
